SELECT id, music_name, artist, album, cover, url, lrc, theme, sort, status, remark, create_time, update_time FROM t_music
(music_name LIKE CONCAT('%', #{conditionVO.keywords}, '%') OR artist LIKE CONCAT('%', #{conditionVO.keywords}, '%'))
AND status = #{conditionVO.status}
ORDER BY sort ASC, id DESC LIMIT #{current}, #{size}
